from datetime import datetime

def parse_date(s: str) -> datetime:
    formats = ["%d/%m/%Y", "%d-%m-%Y", "%Y-%m-%d"]
    for fmt in formats:
        try:
            return datetime.strptime(s, fmt)
        except ValueError:
            continue
    raise ValueError("Date format must be DD/MM/YYYY, DD-MM-YYYY, or YYYY-MM-DD")

